int parseCommandline(int argc, char *argv[], char *filename,
                     int *q, int *v, int *t, int *p, int *d, int *size) {
    int i;
    if (argc < 2) return 1;
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 's':
                    i++;
                    *size = std::atoi(argv[i]);
                    std::printf("Create matrix internally in parse, size = %d \n", *size);
                    break;
                case 'f':
                    i++;
                    std::strncpy(filename, argv[i], 100);
                    std::printf("Read file from %s \n", filename);
                    break;
                case 'h':
                    return 1;
                case 'q':
                    *q = 1;
                    break;
                case 'v':
                    *v = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    *p = std::atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = std::atoi(argv[i]);
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0))
        return 1;
    return 0;
}

